local ipairs = ipairs
local ChatType = ChatType
local LxDataHelper = LxDataHelper

local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxChatHandler:LxBaseHandler
local LxChatHandler = classX("LxChatHandler", LxBaseHandler)

function LxChatHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxChatHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxChatHandler:ClearHandler()
    self._chatMod = nil
    LxBaseHandler.ClearHandler(self)
end

function LxChatHandler:InitOk()

end

-- 完成登录后
function LxChatHandler:LoginOk()

end

-- 初始化协议
function LxChatHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.ChatResp, self.OnChatResp, self)
    self:AddMsgHandler(LxProtoIds.ChatReportResp, self.OnChatReportResp, self)
    self:AddMsgHandler(LxProtoIds.ChatMsgPushResp, self.OnChatMsgPushResp, self)
    self:AddMsgHandler(LxProtoIds.ChatSettingResp, self.OnChatSettingResp, self)
    self:AddMsgHandler(LxProtoIds.ChatLikeResp, self.OnChatLikeResp, self)
    self:AddMsgHandler(LxProtoIds.ChatLikeCntResp, self.OnChatLikeCntResp, self)
end

-- 发送聊天
function LxChatHandler:ChatReq(param)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ChatReq)
    local chat = proto.chat
    chat.channel = param.channel
    chat.type = param.type
    chat.msg = param.msg
    chat.sendTime = GetTimestamp()
    chat.sender["roleId"] = ModuleCenter.Login:GetRoleId()
    chat.target["roleId"] = param.target and param.target.roleId or 0
    if param.specialMsg then
        chat.specialMsg = param.specialMsg
    end
    --if param.shareDataObj then
    --    chat.shareDataObj.rawShareData = param.shareDataObj
    --end
    if param.shareRefId then
        chat.shareRefId = param.shareRefId
    end
    self._send_proto = chat
    SendMessage(LxProtoIds.ChatReq, proto)
end

-- 发送聊天 返回
function LxChatHandler:OnChatResp(pb)
    if self._send_proto then
        local param = {
            channel = self._send_proto.channel,
            type = self._send_proto.type,
        }

        if param.type ~= ChatType.Acoustic then
            -- 传音
            ModuleCenter.Chat:SaveSendMsgTime(param.channel)
        end
        FireEvent(EventNames.CHAT_SEND_MSG_SUCCESS, param)
    end
end

-- 推送聊天消息
function LxChatHandler:OnChatMsgPushResp(pb)
    local LxChatModule = ModuleCenter.Chat
    local LxLoginModule = ModuleCenter.Login
    if pb.first then
        LxChatModule:ClearChatListData()
    end
    local typeMap = {}
    for k, v in ipairs(pb.chats) do
        local info = {}
        info.id = v.id
        info.likeCnt = v.likeCnt
        info.like = v.like
        ModuleCenter.Chat:AddChatLikeInfo(info)
        local channel = v.channel
        v.sendTime = tonumber(v.sendTime)
        if v.type == ChatType.System or v.type == ChatType.Assist then
            v.msg = LxDataHelper.FormatChatNotice(v.newsId, v.msg)
        end

        if v.type == ChatType.Call and LxLoginModule:IsSelf(v.target.roleId) then
            -- @我
            LxChatModule:AddCallMeMsg(channel, v)
        end
        if v.channel == ChatChannel.Private then
            LxChatModule:AddPrivateChat(v)
        else
            LxChatModule:AddChatMsgByChannel(channel, v)
        end

        typeMap[channel] = true

        if not pb.first and v.lamp then
            if v.type == ChatType.Acoustic then
                -- 传音
                local _, msg = MgrCenter.MaskWordMgr:FilterWord(v.msg, nil, true, 2, ModuleCenter.Chat:GetEmojiYellowFaceMap())
                local roleInfo = v.sender
                local serverName = ModuleCenter.Login:GetServerNameExMySef(roleInfo.serverId)
                local strName = roleInfo.name
                if serverName ~= "" then
                    strName = strName .. "[" .. serverName .. "]"
                end
                strName = "<color=#ffb25f>" .. strName .. "：</color>"
                msg = LxChatModule:MsgToYellowFaceMsg(msg)
                msg = strName .. msg
                FireEvent(EventNames.CHAT_ACOUSTIC, msg)
            elseif v.type == ChatType.System then
                -- 系统
                FireEvent(EventNames.CHAT_NOTICE, LxChatModule:MsgToYellowFaceMsg(v.msg))
            end
        end
    end
    if not pb.first then
        FireEvent(EventNames.CHAT_NEWMSG, typeMap)
    end
    if typeMap[ChatChannel.Private] then
        local change, list = ModuleCenter.Chat:GetPrivateRoleIdList()
        if change then
            HandlerCenter.Common:CheckOfflineTimeReq(list)
        end
    end

    local uiCtrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.Chat)
    local channel = nil
    local privateRoleId = nil
    if uiCtrl then
        if uiCtrl:InChat() then
            channel = uiCtrl:GetCurChatChannel()
            if channel == ChatChannel.Private then
                channel = nil
                privateRoleId = uiCtrl:GetCurPrivateChatRoleId()
            end
        end
    end
    local redMap = LxChatModule:GetRedMap(channel, privateRoleId)
    if redMap then
        FireEvent(EventNames.CHAT_RED_CHANGE, redMap)
    end
end

-- 举报聊天内容
function LxChatHandler:ChatReportReq(param)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ChatReportReq)

    for k, v in pairs(param) do
        proto[k] = v
    end

    SendMessage(LxProtoIds.ChatReportReq, proto)
end

-- 举报聊天内容 返回
function LxChatHandler:OnChatReportResp(pb)
    ShowSysMsg(I18nText(3050))
    ClosePanel(UiNames.ChatReport)
end

-- 聊天设置
function LxChatHandler:ChatSettingReq(refId,open)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ChatSettingReq)
    proto.refId = refId
    proto.open = open
    SendMessage(LxProtoIds.ChatSettingReq, proto)
end

-- 聊天设置 返回
function LxChatHandler:OnChatSettingResp(pb)
    ModuleCenter.Chat:SetChatSetting(pb.refId,pb.open)
end


-- 聊天点赞/反对
function LxChatHandler:ChatLikeReq(id,channel,cancel)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ChatLikeReq)
    proto.id = id
    proto.channel = channel
    proto.cancel = cancel
    SendMessage(LxProtoIds.ChatLikeReq, proto)
end

-- 聊天点赞/反对 返回
function LxChatHandler:OnChatLikeResp(pb)
    local id = pb.id
    local cancel = pb.cancel
    ModuleCenter.Chat:ModifyChatLikeState(id,cancel)
    FireEvent(EventNames.CHAT_LIKE_CHAGE)
end

-- 聊天点赞数推送
function LxChatHandler:OnChatLikeCntResp(pb)
    for k, v in ipairs(pb.chats) do
        ModuleCenter.Chat:ModifyChatLikeCnt(v.id,v.likeCnt)
    end
    FireEvent(EventNames.CHAT_LIKE_CHAGE)
end

return LxChatHandler
